//! Emit the Go facade client surface (`client_generated.go`) from catalog IR.

use std::fmt::Write as _;

use crate::doc_render::render_entry_doc_lines;
use crate::emit_client_rs::client_operations;
use crate::error::{GenError, GenResult};
use crate::ir::{Ir, IrBindingSymbol, IrEntryPoint, IrSerializeKind, IrTypeRef};

const HEADER: &str = "\
// Code generated by dto-gen. DO NOT EDIT.\n\
// @generated by dto-gen — do not edit. Regenerate with --go-client-out.\n\n";

/// Emits `rust/bindings/go/client_generated.go`.
///
/// # Errors
///
/// Returns formatting / IR shape failures as [`GenError`].
pub fn emit_client_go(ir: &Ir) -> GenResult<String> {
    let mut ops = client_operations(ir);
    ops.sort_by(|left, right| left.0.names.go.cmp(&right.0.names.go));
    let mut output = String::from(HEADER);
    output.push_str("package solvapay\n\n");
    output.push_str("import (\n");
    output.push_str("\t\"context\"\n");
    output.push_str("\t\"encoding/json\"\n");
    output.push_str(")\n\n");

    for (entry, binding) in &ops {
        write_method(&mut output, entry, binding)?;
    }

    while output.ends_with("\n\n") {
        output.pop();
    }
    if !output.ends_with('\n') {
        output.push('\n');
    }
    Ok(output)
}

fn write_method(
    output: &mut String,
    entry: &IrEntryPoint,
    binding: &IrBindingSymbol,
) -> GenResult<()> {
    let name = entry.names.go.as_str();
    write_godoc(output, entry, name);
    let kind = serialize_kind(binding)?;
    let params = go_params(entry, kind)?;
    let sig = format_go_params(&params);
    let _ = writeln!(
        output,
        "func (c *Client) {name}(ctx context.Context{sig}) (any, error) {{"
    );

    match kind {
        IrSerializeKind::ClientIgnore => {
            output.push_str("\tenvelope, err := c.rt.CallEnvelope(ctx, \"sv_");
            output.push_str(&binding.rust_fn_name);
            output.push_str("\", \"{}\")\n");
        }
        IrSerializeKind::ClientAwait => {
            output.push_str("\targs, err := json.Marshal(params)\n");
            output.push_str("\tif err != nil {\n\t\treturn nil, err\n\t}\n");
            output.push_str("\tenvelope, err := c.rt.CallEnvelope(ctx, \"sv_");
            output.push_str(&binding.rust_fn_name);
            output.push_str("\", string(args))\n");
        }
        IrSerializeKind::ClientSplit => {
            write_split_marshal(output, entry, binding)?;
            output.push_str("\tenvelope, err := c.rt.CallEnvelope(ctx, \"sv_");
            output.push_str(&binding.rust_fn_name);
            output.push_str("\", string(args))\n");
        }
        other => {
            return Err(GenError::Parse(format!(
                "unexpected serialize kind for {}: {other:?}",
                entry.id
            )))
        }
    }

    output.push_str("\tif err != nil {\n\t\treturn nil, err\n\t}\n");
    output.push_str("\tvar out any\n");
    output.push_str("\tif err := decodeEnvelope(envelope, &out); err != nil {\n");
    output.push_str("\t\treturn nil, err\n\t}\n");
    output.push_str("\treturn out, nil\n}\n\n");
    Ok(())
}

fn write_split_marshal(
    output: &mut String,
    entry: &IrEntryPoint,
    binding: &IrBindingSymbol,
) -> GenResult<()> {
    output.push_str("\tpayload := map[string]any{}\n");
    for key in &binding.split_path_refs {
        let param = entry
            .params
            .iter()
            .find(|p| p.name == *key)
            .ok_or_else(|| {
                GenError::Parse(format!(
                    "{}: splitPathRef {key} missing from catalog params",
                    entry.id
                ))
            })?;
        let _ = writeln!(output, "\tpayload[\"{key}\"] = {}", param.names.go);
    }
    // Remaining catalog params are body fields (required or optional maps).
    for param in &entry.params {
        if binding.split_path_refs.iter().any(|k| k == &param.name) {
            continue;
        }
        match &param.ty {
            IrTypeRef::Named(_) | IrTypeRef::Value => {
                if param.required {
                    let _ = writeln!(
                        output,
                        "\tfor k, v := range {} {{\n\t\tpayload[k] = v\n\t}}",
                        param.names.go
                    );
                } else {
                    let _ = writeln!(
                        output,
                        "\tif {} != nil {{\n\t\tfor k, v := range {} {{\n\t\t\tpayload[k] = v\n\t\t}}\n\t}}",
                        param.names.go, param.names.go
                    );
                }
            }
            other => {
                return Err(GenError::Parse(format!(
                    "{}: unsupported ClientSplit body param type {other:?}",
                    entry.id
                )))
            }
        }
    }
    output.push_str("\targs, err := json.Marshal(payload)\n");
    output.push_str("\tif err != nil {\n\t\treturn nil, err\n\t}\n");
    Ok(())
}

#[derive(Debug, Clone)]
struct GoParam {
    name: String,
    ty: String,
}

fn go_params(entry: &IrEntryPoint, kind: IrSerializeKind) -> GenResult<Vec<GoParam>> {
    match kind {
        IrSerializeKind::ClientIgnore => Ok(Vec::new()),
        IrSerializeKind::ClientAwait => Ok(vec![GoParam {
            name: "params".into(),
            ty: "map[string]any".into(),
        }]),
        IrSerializeKind::ClientSplit => {
            let mut params = Vec::new();
            for param in &entry.params {
                let name = param.names.go.clone();
                let ty = match &param.ty {
                    IrTypeRef::String => "string".into(),
                    IrTypeRef::Named(_) | IrTypeRef::Value => "map[string]any".into(),
                    other => {
                        return Err(GenError::Parse(format!(
                            "unsupported Go split param type for {}: {other:?}",
                            entry.id
                        )))
                    }
                };
                params.push(GoParam { name, ty });
            }
            Ok(params)
        }
        other => Err(GenError::Parse(format!(
            "unexpected serialize kind for {}: {other:?}",
            entry.id
        ))),
    }
}

fn format_go_params(params: &[GoParam]) -> String {
    if params.is_empty() {
        return String::new();
    }
    let mut parts = Vec::new();
    for param in params {
        parts.push(format!("{} {}", param.name, param.ty));
    }
    format!(", {}", parts.join(", "))
}

fn serialize_kind(binding: &IrBindingSymbol) -> GenResult<IrSerializeKind> {
    match &binding.call {
        crate::ir::IrBindingCall::Wrap { serialize, .. } => Ok(*serialize),
        crate::ir::IrBindingCall::Verbatim => Err(GenError::Parse(format!(
            "client symbol {} unexpectedly verbatim",
            binding.id
        ))),
    }
}

/// Builds godoc lines: first word is the Go identifier (D19 / §5.6).
fn render_godoc(entry: &IrEntryPoint, name: &str) -> Vec<String> {
    let raw = render_entry_doc_lines(entry, |p| p.names.go.as_str());
    let mut out = Vec::new();
    let mut params = Vec::new();
    let mut returns = None;
    for line in raw {
        if let Some(rest) = line.strip_prefix("@param ") {
            params.push(rest.to_owned());
        } else if let Some(rest) = line.strip_prefix("@returns ") {
            returns = Some(rest.to_owned());
        } else if out.is_empty() {
            if line.starts_with(name) {
                out.push(line);
            } else {
                out.push(format!("{name} {}", uncapitalize(&line)));
            }
        } else {
            out.push(line);
        }
    }
    if out.is_empty() {
        out.push(name.to_owned());
    }
    for param in params {
        let (pname, doc) = split_param_doc(&param);
        if doc.is_empty() {
            out.push(format!("The {pname} parameter."));
        } else {
            out.push(format!("The {pname} parameter is {doc}"));
        }
    }
    if let Some(returns) = returns {
        out.push(format!("Returns {returns}"));
    }
    out
}

fn write_godoc(output: &mut String, entry: &IrEntryPoint, name: &str) {
    for line in render_godoc(entry, name) {
        if line.is_empty() {
            output.push_str("//\n");
        } else {
            let _ = writeln!(output, "// {line}");
        }
    }
}

fn split_param_doc(line: &str) -> (&str, &str) {
    match line.split_once(' ') {
        Some((name, doc)) => (name, doc.trim()),
        None => (line, ""),
    }
}

fn uncapitalize(line: &str) -> String {
    let mut chars = line.chars();
    match chars.next() {
        Some(first) => first.to_lowercase().collect::<String>() + chars.as_str(),
        None => String::new(),
    }
}

#[cfg(test)]
#[allow(clippy::unwrap_used, clippy::expect_used, clippy::panic)]
mod tests {
    use super::*;
    use crate::ir::{
        IrAvailability, IrBindingArtifact, IrBindingCall, IrBindingCatalogLink, IrDefaults,
        IrDocModel, IrEntrySection, IrEnvelopeMode, IrErrorKind, IrLangNames, IrRubyReceiver,
        IrRubyTarget, IrSyncKind,
    };
    use std::collections::BTreeMap;

    #[test]
    fn emits_ctx_first_header_and_godoc_identifier() {
        let mut ir = Ir {
            types: BTreeMap::new(),
            overlay_helpers: BTreeMap::new(),
            overlays: BTreeMap::new(),
            routes: vec![],
            error_templates: crate::ir::IrErrorTemplates::default(),
            entry_points: BTreeMap::new(),
            binding_symbols: BTreeMap::new(),
        };
        ir.entry_points.insert(
            "getMerchant".into(),
            IrEntryPoint {
                id: "getMerchant".into(),
                section: IrEntrySection::Operation,
                names: IrLangNames {
                    ts: "getMerchant".into(),
                    py: "get_merchant".into(),
                    rb: "get_merchant".into(),
                    go: "GetMerchant".into(),
                    rust: "get_merchant".into(),
                },
                optional_on_client: false,
                params: vec![],
                type_params: vec![],
                request: None,
                response: Some("SdkMerchantResponseDto".into()),
                availability: IrAvailability {
                    ts: vec![IrSyncKind::Async],
                    py: vec![IrSyncKind::Async, IrSyncKind::Sync],
                    rb: vec![IrSyncKind::Sync],
                    go: vec![IrSyncKind::Sync],
                    rust: vec![IrSyncKind::Async, IrSyncKind::Sync],
                },
                sync_ts: IrSyncKind::Async,
                ruby_target: IrRubyTarget {
                    owner: "SolvaPay::Client".into(),
                    name: "get_merchant".into(),
                    receiver: IrRubyReceiver::ClientInstance,
                    takes_block: false,
                },
                defaults: IrDefaults::default(),
                errors: vec![IrErrorKind::Api],
                docs: IrDocModel {
                    summary: "Fetch the authenticated merchant profile.".into(),
                    returns: Some("Merchant profile projection.".into()),
                },
            },
        );
        ir.binding_symbols.insert(
            "getMerchant".into(),
            IrBindingSymbol {
                id: "getMerchant".into(),
                core: "solvapay_transport::SolvaPayClient::get_merchant".into(),
                names: IrLangNames {
                    ts: "getMerchant".into(),
                    py: "get_merchant".into(),
                    rb: "get_merchant".into(),
                    go: "GetMerchant".into(),
                    rust: "get_merchant".into(),
                },
                catalog: IrBindingCatalogLink::Operation("getMerchant".into()),
                args: vec![],
                split_path_refs: vec![],
                return_shape: "value".into(),
                sync: IrSyncKind::Async,
                envelope: IrEnvelopeMode::Async,
                artifact: IrBindingArtifact::Client,
                emit_order: 0,
                section: None,
                doc: "Merchant profile.".into(),
                doc_wasm: None,
                rust_fn_name: "get_merchant".into(),
                call: IrBindingCall::Wrap {
                    serialize: IrSerializeKind::ClientIgnore,
                    args: vec![],
                },
                verbatim_body: None,
                verbatim_body_wasm: None,
                dto_type: None,
                core_call: Some("get_merchant".into()),
                client_call_args: vec![],
            },
        );

        let out = emit_client_go(&ir).unwrap();
        assert!(out.contains("// Code generated by dto-gen. DO NOT EDIT."));
        assert!(out.contains("// @generated"));
        assert!(out.contains("func (c *Client) GetMerchant(ctx context.Context) (any, error)"));
        assert!(out.lines().any(|l| l.starts_with("// GetMerchant ")));
        assert!(out.contains("sv_get_merchant"));
        assert!(out.contains("\"{}\""));
    }
}
